const payload = $json.body ?? $json;
if (!payload.title || !payload.start_at || !payload.end_at) {
  return [{ json: { reply: '일정 생성 payload가 올바르지 않습니다.', action: 'calendar-create-error' } }];
}
return [{ json: { title: String(payload.title), start_at: String(payload.start_at), end_at: String(payload.end_at), description: String(payload.message ?? ''), location: String(payload.location ?? '') } }];

const event = $json;
const formatTime = (value) => new Intl.DateTimeFormat('ko-KR', { timeZone: 'Asia/Seoul', month: 'numeric', day: 'numeric', hour: '2-digit', minute: '2-digit', hour12: false }).format(new Date(value));
const title = event.summary || '제목 없는 일정';
const start = event.start?.dateTime ? formatTime(event.start.dateTime) : (event.start?.date || '날짜 미확인');
const end = event.end?.dateTime ? formatTime(event.end.dateTime) : '';
return [{ json: { reply: end ? `${start}부터 ${end}까지 ${title} 일정을 생성했습니다.` : `${start} ${title} 일정을 생성했습니다.`, action: 'calendar-create', event_id: event.id || '' } }];

const payload = $json ?? {};
const rawError = payload.error?.message ?? payload.error ?? payload.message ?? payload.description ?? payload.cause?.message ?? payload.metadata?.error?.message ?? '';
const message = String(rawError || 'Google Calendar workflow execution failed');
const needsReconnect = /(authorization grant|refresh token|oauth|invalid credentials|unauthorized|forbidden|revoked|expired)/i.test(message);
const reply = needsReconnect
  ? 'Google Calendar 연결이 만료되었거나 권한이 끊어져 일정 생성을 완료하지 못했습니다. n8n의 Google Calendar account credential을 다시 연결해 주세요.'
  : `일정 생성 실행 중 오류가 발생했습니다. ${message}`;
return [{ json: { reply, action: 'calendar-create-error', error: message, needs_reconnect: needsReconnect } }];
